parameters.jsCode:
// ============================================================================
// GHOST BUSTER V7.1 - PRE-PROCESSOR (HYBRID)
// Détection CODE en premier, AI pour les cas ambigus
// ============================================================================

// 1. RECUPERATION SECURISEE DES MEMOIRES
let brandMemory = {};
try { brandMemory = $('Load Brand Memory').first().json; } catch(e) {}

const brandEssentials = {
  brand_name: brandMemory.brand_name || 'The Hive',
  tone: brandMemory.tone || {},
  style: brandMemory.style || '',
  colors: {
    primary: brandMemory.colors?.primary || '#000000',
    accent1: brandMemory.colors?.accent1 || '#FF00FF',
    accent2: brandMemory.colors?.accent2 || '#00FFFF'
  },
  main_prompt: brandMemory.prompt_assets0 || '',
  tagline: brandMemory.tagline || ''
};

// 2. RECUPERATION HYBRIDE DE L'INPUT
let userInput = {};
try {
  userInput = $('When Executed by Another Workflow').first().json;
} catch (error) {
  try {
    userInput = $('Webhook Trigger').first().json;
  } catch (e) {
    try {
      userInput = $('When chat message received').first().json;
    } catch (e2) {
      userInput = $input.first().json;
    }
  }
}

const inputBody = userInput.body || userInput;

// 3. GHOST BUSTER: Clean image_base64
let rawImage = inputBody.image_base64 || inputBody.image || null;
let cleanedImage = null;
let hasValidImage = false;

if (rawImage && typeof rawImage === 'string') {
  const imageStr = rawImage.trim().toLowerCase();
  const isGhost = (
    imageStr === 'null' ||
    imageStr === 'undefined' ||
    imageStr === '' ||
    imageStr === 'none' ||
    imageStr.length < 100
  );

  if (!isGhost) {
    cleanedImage = rawImage;
    hasValidImage = true;
  }
}

// 4. Prepare message for AI
const message = inputBody.chatInput || inputBody.message || inputBody.query || '';
const messageLower = message.toLowerCase();

// ============================================================================
// 5. DETECTION PAR MOTS-CLES (PRIORITAIRE - NE FAIT PAS CONFIANCE A L'IA)
// ============================================================================
let forced_content_type = null;
let forced_tool = null;
let detection_reason = null;

// VIDEO KEYWORDS - PRIORITE ABSOLUE
const videoKeywords = ['video', 'vidéo', 'clip', 'reel', 'film', 'animation', 'motion', 'cinematic', 'footage'];
const hasVideoKeyword = videoKeywords.some(kw => messageLower.includes(kw));

if (hasVideoKeyword) {
  forced_content_type = 'video';
  forced_tool = 'runway_gen3';
  detection_reason = 'FORCED_VIDEO: Mot-cle video detecte dans: ' + message.substring(0, 100);
}

// COPY KEYWORDS (seulement si pas VIDEO)
if (!forced_content_type) {
  const copyKeywords = ['article', 'blog', 'blogue', 'redige', 'ecris', 'texte seo', 'copywriting'];
  const hasCopyKeyword = copyKeywords.some(kw => messageLower.includes(kw));

  if (hasCopyKeyword) {
    forced_content_type = 'copy';
    forced_tool = 'copywriting_pro';
    detection_reason = 'FORCED_COPY: Mot-cle copywriting detecte';
  }
}

return [{
  json: {
    user_message: message,
    session_id: inputBody.session_id || 'session_' + Date.now(),
    has_image: hasValidImage,
    brand: brandEssentials,
    raw_image: cleanedImage,
    original_input: inputBody,
    forced_content_type: forced_content_type,
    forced_tool: forced_tool,
    detection_reason: detection_reason
  }
}];

// ============================================================================
// GHOST BUSTER V7.1 - POST-PROCESSOR (HYBRID)
// Respecte la detection CODE, utilise AI seulement si pas de forced_type
// ============================================================================

const aiResponse = $input.first().json;
const preProcessorData = $('Pre-Processor').first().json;

// ============================================================================
// 1. PRIORITE ABSOLUE: Detection forcee par mots-cles (du Pre-Processor)
// ============================================================================
const forcedType = preProcessorData.forced_content_type;
const forcedTool = preProcessorData.forced_tool;
const forcedReason = preProcessorData.detection_reason;

let classification = {
  content_type: 'image',
  recommended_tool: 'nano_banana_pro',
  platform: 'meta_feed',
  confidence: 0.5,
  reasoning: 'Default fallback'
};

// SI DETECTION FORCEE -> On ignore completement l'AI
if (forcedType && forcedTool) {
  classification = {
    content_type: forcedType,
    recommended_tool: forcedTool,
    platform: forcedType === 'video' ? 'meta_reel' : 'meta_feed',
    confidence: 1.0,
    reasoning: forcedReason
  };
} else {
  // 2. Sinon, parser la reponse AI pour les cas ambigus
  try {
    const outputText = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);
    const jsonMatch = outputText.match(/\{[\s\S]*?\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      classification = {
        content_type: parsed.content_type || 'image',
        recommended_tool: parsed.recommended_tool || 'nano_banana_pro',
        platform: parsed.platform || 'meta_feed',
        confidence: parsed.confidence || 0.9,
        reasoning: 'AI: ' + (parsed.reasoning || 'AI classification')
      };
    }
  } catch (e) {
    classification.reasoning = 'Parsing failed, using defaults: ' + e.message;
  }
}

// Map tool to content type (safety check)
const toolMap = {
  'nano_banana_pro': 'image',
  'runway_gen3': 'video',
  'copywriting_pro': 'copy'
};

const contentTypeMap = {
  'image': 'nano_banana_pro',
  'video': 'runway_gen3',
  'copy': 'copywriting_pro'
};

// Ensure consistency (seulement si PAS force)
if (!forcedType) {
  if (classification.recommended_tool && toolMap[classification.recommended_tool]) {
    classification.content_type = toolMap[classification.recommended_tool];
  } else if (classification.content_type && contentTypeMap[classification.content_type]) {
    classification.recommended_tool = contentTypeMap[classification.content_type];
  }
}

// Determine vision mode
let visionMode = 'disabled';
if (preProcessorData.has_image) {
  if (classification.content_type === 'video') visionMode = 'image_to_video';
  else if (classification.content_type === 'copy') visionMode = 'image_to_text';
  else visionMode = 'image_analysis';
}

// Prepare binary data if image exists
let binaryData = undefined;
if (preProcessorData.has_image && preProcessorData.raw_image) {
  const cleanedImage = preProcessorData.raw_image;
  const matches = cleanedImage.match(/^data:(.+);base64,(.+)$/);
  if (matches) {
    binaryData = { image: { data: matches[2], mimeType: matches[1], fileName: 'context.png' } };
  } else {
    binaryData = { image: { data: cleanedImage, mimeType: 'image/png', fileName: 'context.png' } };
  }
}

// Detected mode
let detectedMode = 'production';
const message = preProcessorData.user_message.toLowerCase();
const brainstormKeywords = ['idee', 'idees', 'concept', 'brainstorm', 'propose', 'suggere'];
if (brainstormKeywords.some(kw => message.includes(kw))) {
  detectedMode = 'brainstorming';
}

// ─────────────────────────────────────────────────────────────────────────
// OUTPUT V7.1 - Same structure as Ghost Buster V6.9 for compatibility
// ─────────────────────────────────────────────────────────────────────────
return [{
  json: {
    user_request: {
      message: preProcessorData.user_message,
      original_query: preProcessorData.user_message,
      session_id: preProcessorData.session_id,
      timestamp: new Date().toISOString()
    },

    image_input: {
      has_valid_image: preProcessorData.has_image,
      status: preProcessorData.has_image ? 'VALID' : 'NO_IMAGE',
      cleaned_value: preProcessorData.has_image ? '[IMAGE_BINARY_ATTACHED]' : null
    },

    detected_mode: detectedMode,
    content_type: classification.content_type,
    vision_mode: visionMode,
    platform: classification.platform,

    recommended_tool: classification.recommended_tool,
    tool_selection_reason: classification.reasoning,

    brand: preProcessorData.brand,

    system_instruction_add: preProcessorData.has_image
      ? '[VISION: ' + visionMode.toUpperCase() + '] Image fournie.'
      : '',

    tools_available: ['copywriting_pro', 'nano_banana_pro', 'runway_gen3'],

    ai_classification: classification,

    // V7.1: Debug info
    forced_detection: {
      was_forced: !!(forcedType && forcedTool),
      forced_type: forcedType,
      forced_tool: forcedTool,
      reason: forcedReason
    }
  },
  binary: binaryData
}];
